// swift-tools-version:5.10
import PackageDescription
import Foundation

// The engine (HyperfocalKit), vendored Adobe DNG SDK, and CLI live here as a
// SwiftPM package. The Hyperfocal app itself is an Xcode target (generated by
// XcodeGen from project.yml) that depends on this package.
//
// Cross-platform note: on Apple platforms the engine decodes/encodes through
// ImageIO/CoreImage and registers through Vision. On Linux those frameworks
// don't exist, so the engine talks to a C-ABI shim (`CImaging`) over
// libtiff/libpng/libjpeg-turbo/LibRaw/lcms2/exiv2/OpenCV. See
// Docs/cross-platform-plan.md.

// Split a pkg-config invocation's output into individual flags. Run at manifest
// evaluation time so the multiarch include/lib paths come from the system,
// not hardcoded. Returns [] if pkg-config isn't present (non-Linux hosts).
func pkgConfig(_ mode: String, _ packages: [String]) -> [String] {
    let proc = Process()
    proc.executableURL = URL(fileURLWithPath: "/usr/bin/env")
    proc.arguments = ["pkg-config", mode] + packages
    let pipe = Pipe()
    proc.standardOutput = pipe
    proc.standardError = FileHandle.nullDevice
    guard (try? proc.run()) != nil else { return [] }
    proc.waitUntilExit()
    let data = pipe.fileHandleForReading.readDataToEndOfFile()
    let text = String(data: data, encoding: .utf8) ?? ""
    return text.split(whereSeparator: { $0 == " " || $0 == "\n" || $0 == "\t" })
        .map(String.init).filter { !$0.isEmpty }
}

// True if pkg-config knows the package (exit status 0). Used to detect an
// optional OpenCV install on macOS for the Phase 1.5 registration A/B — absent
// it, macOS builds Vision-only exactly as before.
func pkgExists(_ pkg: String) -> Bool {
    let proc = Process()
    proc.executableURL = URL(fileURLWithPath: "/usr/bin/env")
    proc.arguments = ["pkg-config", "--exists", pkg]
    proc.standardError = FileHandle.nullDevice
    guard (try? proc.run()) != nil else { return false }
    proc.waitUntilExit()
    return proc.terminationStatus == 0
}

// Opt-in wgpu compute backend (cross-platform-plan Phase 4): build with
// HYPERFOCAL_WGPU=1 and a wgpu-native prebuilt release at WGPU_ROOT
// (default: a `wgpu-native` checkout beside this repo). Opt-in like the
// OpenCV A/B: the backend is under construction and must not gate anyone's
// build. Legal on macOS too (decided 2026-07-21) — production Mac builds
// keep Metal (this env is never set for them), but the parity suite runs
// through wgpu's Metal backend, which lets cross-engine WGSL changes be
// gated on a Mac before they reach Windows/Linux (that run caught the
// plane_upsample/pyr_upsample binding collision the day it was written).
// Explicit env opt-in only — no auto-detection, so a merely-present
// wgpu-native checkout can't contaminate app builds (the OpenCV lesson).
// Every target that imports HyperfocalKit rebuilds the CWgpu Clang module
// with its own flags, so the include path rides on all of them (wgpuXcc).
var wgpuEnabled = false
var wgpuRoot = ""
var wgpuXcc: [SwiftSetting] = []
if ProcessInfo.processInfo.environment["HYPERFOCAL_WGPU"] == "1" {
    wgpuEnabled = true
    wgpuRoot = ProcessInfo.processInfo.environment["WGPU_ROOT"]
        ?? FileManager.default.currentDirectoryPath + "/../wgpu-native"
    wgpuXcc = [.unsafeFlags(["-Xcc", "-I\(wgpuRoot)/include"])]
}

#if os(Windows)
// vcpkg supplies every C library on Windows (no pkg-config; see
// Docs/cross-platform-plan.md). The installed tree is resolved at
// manifest-eval time from VCPKG_ROOT (falling back to a `vcpkg` checkout
// beside this repo) and VCPKG_TRIPLET.
let winEnv = ProcessInfo.processInfo.environment
let vcpkgRoot = winEnv["VCPKG_ROOT"]
    ?? FileManager.default.currentDirectoryPath + "\\..\\vcpkg"
let vcpkgTriplet = winEnv["VCPKG_TRIPLET"] ?? "arm64-windows"
let vcpkgPrefix = "\(vcpkgRoot)\\installed\\\(vcpkgTriplet)"
#endif

// Platform flag the vendored DNG SDK selects its OS layer on (dng_flags.h has
// first-class qLinux support; only zlib is linked — XMP/JPEG/JXL are compiled
// out via the qDNG* defines below).
#if os(macOS)
let dngPlatformDefine: CXXSetting = .define("qMacOS", to: "1")
#elseif os(Linux)
let dngPlatformDefine: CXXSetting = .define("qLinux", to: "1")
#else
let dngPlatformDefine: CXXSetting = .define("qWinOS", to: "1")
#endif

// HyperfocalKit dependencies: the DNG SDK everywhere, plus the imaging shim on
// non-Apple platforms (appended below).
var hyperfocalKitDeps: [Target.Dependency] = ["CDNGSDK"]
var extraTargets: [Target] = []
var extraProducts: [Product] = []

// Warnings are errors on the first-party Swift targets (Kit, AppCore,
// Bridge, CLI). Scoped per build host because this #if evaluates on the
// building machine and the three active toolchains (Windows 6.3.3, Xcode,
// Linux 6.1) warn differently: Windows is enforced (verified clean
// 2026-07-22 — Sendable captures, strdup, replaceItemAt all fixed); a
// Mac/Linux session should extend the #if to its own OS after one clean
// local build rather than discover breakage from another platform's flag.
#if os(Windows)
let warningsAsErrors: [SwiftSetting] = [.unsafeFlags(["-warnings-as-errors"])]
#else
let warningsAsErrors: [SwiftSetting] = []
#endif

// HyperfocalKit's own build settings, extended per-platform below.
var kitSwiftSettings: [SwiftSetting] = warningsAsErrors + [
    // The engine's per-pixel loops are ~30-50x slower at -Onone — a 45MP depth
    // regularization goes from ~30s to tens of minutes. Keep the engine
    // optimized even in Debug builds; the app layer stays debuggable.
    // (-wmo would help equally off Apple platforms — per-file debug compiles
    // leave cross-file helpers as unspecialized calls in per-pixel loops —
    // but it breaks SwiftPM's incremental driver; PortableSIMD is @inlinable
    // instead, which is also how Apple's real `simd` module avoids the same
    // trap. See the header note there before adding per-pixel helpers.)
    .unsafeFlags(["-O"], .when(configuration: .debug)),
]

// The shared model layer as a real module (cross-platform-plan 0d): the
// probe, the Qt bridge, and (eventually) the Linux shell consume it as a
// dependency. The Mac app still compiles the same files directly into its
// target (App/project.yml path reference) — no module boundary there.
// -enable-testing in every configuration so the probe's @testable import
// works: the probe is a white-box regression harness, and its deep reach
// into model internals must not force those internals public — the public
// surface is defined by real shell clients (the bridge).
// Off Apple, ObservableObject/@Published come from OpenCombine.
var appCoreDeps: [Target.Dependency] = ["HyperfocalKit"]
// ObservableObject/@Published come from OpenCombine off Apple platforms.
// This is a build-time platform condition, NOT a manifest #if: package
// dependencies must be identical on every platform or each OS rewrites
// Package.resolved to its own view (the pin ping-pongs mac↔linux).
appCoreDeps.append(.product(name: "OpenCombine", package: "OpenCombine",
                            condition: .when(platforms: [.linux, .windows, .android])))
#if !os(macOS)
// `import zlib` is an Apple-SDK module; elsewhere ProjectStore's crc32 comes
// from a minimal system-library shim over <zlib.h>. vcpkg's zlib names its
// import library z.lib, so the modulemap's `link "z"` holds on Windows too.
// (Local targets don't affect Package.resolved, so this #if is fine.)
appCoreDeps.append("CZlib")
extraTargets.append(.systemLibrary(name: "CZlib", path: "Sources/CZlib"))
#endif
var appCoreSwiftSettings: [SwiftSetting] = warningsAsErrors + [.unsafeFlags(["-enable-testing"])]
#if os(Windows)
// CZlib's <zlib.h> and the link path both come from vcpkg.
appCoreSwiftSettings.append(.unsafeFlags(
    ["-Xcc", "-I\(vcpkgPrefix)\\include", "-L", "\(vcpkgPrefix)\\lib"]))
#endif
appCoreSwiftSettings.append(contentsOf: wgpuXcc)
extraTargets.append(
    .target(
        name: "AppCore",
        dependencies: appCoreDeps,
        path: "AppCore",
        swiftSettings: appCoreSwiftSettings
    )
)
// C-ABI bridge the Qt shell drives (cross-platform-plan Phase 2): a
// SwiftPM dynamic library so one product definition serves macOS and
// Linux. A development artifact for the Qt shell — never shipped with
// the Mac app.
extraTargets.append(
    .target(
        name: "HyperfocalBridge",
        dependencies: ["AppCore", "HyperfocalKit"],
        path: "Bridge",
        swiftSettings: warningsAsErrors + wgpuXcc
    )
)
extraProducts.append(
    .library(name: "HyperfocalBridge", type: .dynamic,
             targets: ["HyperfocalBridge"])
)

#if os(macOS)
// The probe drives AppKit-side checks too (pasteboards, CG parity) —
// macOS only; the Linux gate is the CLI synth→fuse→compare path.
extraTargets.append(
    .executableTarget(
        name: "retouch-probe",
        dependencies: ["AppCore", "HyperfocalKit"],
        path: "Probe"
    )
)
// Phase 1.5 registration A/B (Docs/cross-platform-plan.md decision 2):
// HYPERFOCAL_OPENCV_AB=1 at build time compiles a small OpenCV-only
// registration target so the fusion pipeline can run OpenCV registration on
// macOS and be compared against Vision on identical frames; selected at
// runtime via HYPERFOCAL_REGISTER=opencv (see Aligner). Explicitly opt-in,
// never auto-detected: with Homebrew OpenCV merely installed, auto-linking
// put its ad-hoc-signed dylibs into HyperfocalKit and thus the *app*, whose
// library validation rightly refuses them (different Team IDs) — dyld killed
// the app at launch. The A/B is a CLI-only affair; the app must always build
// Vision-only. Homebrew ships OpenCV 5 (module `opencv5`); Linux/older
// installs use `opencv4`. Take whichever pkg-config knows.
if ProcessInfo.processInfo.environment["HYPERFOCAL_OPENCV_AB"] == "1",
   let cvPkg = ["opencv5", "opencv4"].first(where: pkgExists) {
    extraTargets.append(
        .target(
            name: "COpenCVRegister",
            path: "Sources/COpenCVRegister",
            publicHeadersPath: "include",
            cxxSettings: [
                .unsafeFlags(pkgConfig("--cflags", [cvPkg])),
                .unsafeFlags(["-Wno-deprecated-declarations"]),
            ],
            linkerSettings: [
                .unsafeFlags(pkgConfig("--libs", [cvPkg])),
                .linkedLibrary("c++"),
            ]
        )
    )
    hyperfocalKitDeps.append("COpenCVRegister")
    kitSwiftSettings.append(.define("HYPERFOCAL_HAVE_OPENCV"))
}
#elseif os(Linux)
// The C-ABI imaging shim over the system libraries. pkg-config supplies the
// (multiarch) include and link flags at manifest-eval time.
let imagingPkgs = ["libtiff-4", "libpng", "libjpeg", "lcms2", "libraw", "opencv4", "exiv2"]
extraTargets.append(
    .target(
        name: "CImaging",
        path: "Sources/CImaging",
        publicHeadersPath: "include",
        cxxSettings: [
            .unsafeFlags(pkgConfig("--cflags", imagingPkgs)),
            .unsafeFlags(["-Wno-deprecated-declarations"]),
            // Same rationale as HyperfocalKit's debug -O: the shim's
            // per-pixel decode/convert loops are ~10x slower at -O0.
            .unsafeFlags(["-O2"], .when(configuration: .debug)),
        ],
        linkerSettings: [
            // LibRaw's pkg-config Libs line carries compile flags (-fopenmp,
            // -pthread) the Swift link driver rejects; map them to the runtime
            // libraries they imply so LibRaw's parallel decode still links.
            .unsafeFlags(pkgConfig("--libs", imagingPkgs).compactMap {
                switch $0 {
                case "-fopenmp": return "-lgomp"
                case "-pthread": return "-lpthread"
                // Ubuntu's opencv4.pc links every module — including
                // highgui/cvv/viz, which drag Qt5 into any process loading
                // this library. The Qt 6 shell is such a process, and
                // Qt5 + Qt6 together corrupt memory during loader init
                // (identical symbol names, incompatible layouts). Link only
                // the modules the shim uses.
                case let lib where lib.hasPrefix("-lopencv_"):
                    return ["-lopencv_core", "-lopencv_imgproc",
                            "-lopencv_features2d", "-lopencv_calib3d",
                            "-lopencv_video"].contains(lib) ? lib : nil
                default: return $0
                }
            }),
            .linkedLibrary("stdc++"),
        ]
    )
)
hyperfocalKitDeps.append("CImaging")
#elseif os(Windows)
// The same C-ABI imaging shim, with the libraries supplied by vcpkg
// (Docs/cross-platform-plan.md). No pkg-config on Windows: the installed
// tree is resolved at manifest-eval time from VCPKG_ROOT (falling back to
// a `vcpkg` checkout beside this repo) and VCPKG_TRIPLET.
// Import-library names as vcpkg builds them (dynamic triplet; raw_r is
// LibRaw's thread-safe build — the only one vcpkg ships).
let winImagingLibs = ["tiff", "libpng16", "jpeg", "lcms2", "raw_r", "exiv2",
                      "opencv_core4", "opencv_imgproc4", "opencv_features2d4",
                      "opencv_calib3d4", "opencv_video4"]
extraTargets.append(
    .target(
        name: "CImaging",
        path: "Sources/CImaging",
        publicHeadersPath: "include",
        cxxSettings: [
            .unsafeFlags(["-I", vcpkgPrefix + "\\include",
                          // OpenCV nests its headers one level down, as on Linux.
                          "-I", vcpkgPrefix + "\\include\\opencv4"]),
            // Same rationale as HyperfocalKit's debug -O: the shim's
            // per-pixel decode/convert loops run in the dev loop (the Qt
            // shell uses the debug bridge) and are ~10x slower at -O0.
            .unsafeFlags(["-O2"], .when(configuration: .debug)),
        ],
        linkerSettings: [
            .unsafeFlags(["-L" + vcpkgPrefix + "\\lib"]),
        ] + winImagingLibs.map { .linkedLibrary($0) }
    )
)
hyperfocalKitDeps.append("CImaging")
#endif

// zlib for the DNG SDK: the system library on Apple/Linux; on Windows the
// vcpkg build (which also names its import library z.lib), located via -I/-L.
var dngCxxExtra: [CXXSetting] = []
var dngLinkerSettings: [LinkerSetting] = [.linkedLibrary("z")]
#if os(Windows)
dngCxxExtra = [.unsafeFlags(["-I", vcpkgPrefix + "\\include"])]
dngLinkerSettings.insert(.unsafeFlags(["-L" + vcpkgPrefix + "\\lib"]), at: 0)
#endif

var kitLinkerSettings: [LinkerSetting] = []
var cliSwiftSettings: [SwiftSetting] = warningsAsErrors
var cliLinkerSettings: [LinkerSetting] = []
#if os(Windows)
// UTF-8 active code page for the process (Windows residual 1): the C
// imaging stack opens files through ANSI char* APIs; this manifest makes
// them interpret the UTF-8 paths Swift passes. Absolute path — the linker
// runs with a build-directory cwd.
cliLinkerSettings.append(.unsafeFlags([
    "-Xlinker", "/MANIFEST:EMBED",
    "-Xlinker", "/MANIFESTINPUT:" + FileManager.default.currentDirectoryPath
        + "\\Scripts\\windows-utf8.manifest",
]))
#endif
if wgpuEnabled {
    extraTargets.append(.systemLibrary(name: "CWgpu", path: "Sources/CWgpu"))
    hyperfocalKitDeps.append("CWgpu")
    kitSwiftSettings.append(.define("HYPERFOCAL_HAVE_WGPU"))
    kitSwiftSettings.append(contentsOf: wgpuXcc)
    cliSwiftSettings.append(.define("HYPERFOCAL_HAVE_WGPU"))
    cliSwiftSettings.append(contentsOf: wgpuXcc)
    kitLinkerSettings.append(.unsafeFlags(["-L\(wgpuRoot)/lib"]))
    #if os(Windows)
    kitLinkerSettings.append(.linkedLibrary("wgpu_native.dll"))
    #else
    // HYPERFOCAL_WGPU_STATIC=1 links the release archive's libwgpu_native.a
    // instead of the dylib — no runtime library to deploy beside the
    // binary. Verified on macOS (parity suite, no DYLD_LIBRARY_PATH);
    // -lwgpu_native would still pick the dylib when both files sit in
    // lib/, hence the explicit archive path.
    if ProcessInfo.processInfo.environment["HYPERFOCAL_WGPU_STATIC"] == "1" {
        kitLinkerSettings.append(.unsafeFlags(["\(wgpuRoot)/lib/libwgpu_native.a"]))
    } else {
        kitLinkerSettings.append(.linkedLibrary("wgpu_native"))
    }
    #endif
}

var targets: [Target] = [
    .target(
        name: "CDNGSDK",
        path: "Vendor/dng_sdk",
        exclude: [
            "DNG_ReadMe.txt",
            "source/dng_validate.cpp",
            "source/dng_jxl.cpp",
            "source/dng_xmp.cpp",
            "source/dng_xmp_sdk.cpp",
            "source/dng_update_meta.cpp",
            "jxl_headers",
        ],
        sources: ["source", "shim"],
        publicHeadersPath: "include",
        cxxSettings: [
            .headerSearchPath("source"),
            .headerSearchPath("jxl_headers"),
            dngPlatformDefine,
            .define("qDNGUseXMP", to: "0"),
            .define("qDNGXMPFiles", to: "0"),
            .define("qDNGXMPDocOps", to: "0"),
            .define("qDNGUseLibJPEG", to: "0"),
            .define("qDNGValidate", to: "0"),
            .define("NDEBUG"),
            // Adobe's code references APIs deprecated since macOS 10.5;
            // not ours to fix. (unsafeFlags would block use of this package
            // as a remote dependency — acceptable for an app repo.)
            .unsafeFlags(["-Wno-deprecated-declarations"]),
        ] + dngCxxExtra,
        linkerSettings: dngLinkerSettings
    ),
    .target(
        name: "HyperfocalKit",
        dependencies: hyperfocalKitDeps,
        swiftSettings: kitSwiftSettings,
        linkerSettings: kitLinkerSettings
    ),
    .executableTarget(
        name: "hyperfocal-cli",
        dependencies: [
            "HyperfocalKit",
            .product(name: "ArgumentParser", package: "swift-argument-parser"),
        ],
        swiftSettings: cliSwiftSettings,
        linkerSettings: cliLinkerSettings
    ),
]
targets.append(contentsOf: extraTargets)

let package = Package(
    name: "HyperfocalKit",
    platforms: [.macOS(.v14)],
    products: [
        .library(name: "HyperfocalKit", targets: ["HyperfocalKit"]),
        .executable(name: "hyperfocal-cli", targets: ["hyperfocal-cli"]),
    ] + extraProducts,
    // Unconditional on every platform (see the OpenCombine note above):
    // a #if here makes each OS resolve a different dependency set and
    // rewrite Package.resolved with its own pins.
    dependencies: [
        .package(url: "https://github.com/apple/swift-argument-parser", from: "1.3.0"),
        .package(url: "https://github.com/OpenCombine/OpenCombine.git", from: "0.14.0"),
    ],
    targets: targets,
    cxxLanguageStandard: .cxx17
)
